package com.example.comments.controller;

import com.example.comments.model.Comment;
import com.example.comments.service.CommentService;
import com.example.comments.util.HtmlSanitizer;
import org.springframework.beans.factory.annotation.Autowired;
import org.springframework.stereotype.Controller;
import org.springframework.ui.Model;
import org.springframework.web.bind.annotation.GetMapping;
import org.springframework.web.bind.annotation.PostMapping;
import org.springframework.web.bind.annotation.RequestParam;

import java.util.List;
import java.util.stream.Collectors;

@Controller
public class CommentController {

    @Autowired
    private CommentService commentService;

    @Autowired
    private HtmlSanitizer htmlSanitizer;

    @GetMapping("/comments")
    public String showComments(Model model) {
        List<Comment> rawComments = commentService.getAllComments();

        // Sanitize each comment's HTML content before passing to the view
        List<Comment> sanitizedComments = rawComments.stream()
                .map(comment -> {
                    Comment sanitized = new Comment();
                    sanitized.setId(comment.getId());
                    sanitized.setUsername(comment.getUsername());
                    sanitized.setContent(htmlSanitizer.sanitize(comment.getContent()));
                    sanitized.setCreatedAt(comment.getCreatedAt());
                    return sanitized;
                })
                .collect(Collectors.toList());

        model.addAttribute("comments", sanitizedComments);
        return "comments";
    }

    @PostMapping("/comments")
    public String addComment(@RequestParam("username") String username,
                             @RequestParam("content") String content) {
        Comment comment = new Comment();
        comment.setUsername(username);
        comment.setContent(content);
        commentService.saveComment(comment);
        return "redirect:/comments";
    }
}